```
const PROCESSING_FEE = 5;                                          // 1 constant (5), 1 assignment (PROCESSING_FEE = ...)

const BASE_PREMIUMS: Record<string, number> = {                    // 1 assignment (BASE_PREMIUMS = ...)
  sword: 100,                                                      // 1 constant ("sword" implicit key), 1 constant (100)
  amulet: 60,                                                      // 1 constant ("amulet" implicit key), 1 constant (60)
};

const basePremium = (item: any): number =>                          // 1 binding (item)
  BASE_PREMIUMS[item.type] ?? 0;                                    // 1 invocation ([] lookup), 1 invocation (??), 1 constant (0)

export const processScenario = (scenario: any): any => {            // 1 binding (scenario)
  const results = scenario.steps.map((step: any) => {               // 1 binding (results), 1 binding (step), 1 invocation (map)
    const itemsTotal = step.items.reduce(                           // 1 binding (itemsTotal), 1 invocation (reduce)
      (sum: number, item: any) => sum + basePremium(item),          // 2 bindings (sum, item), 1 invocation (+), 1 invocation (basePremium)
      0,                                                            // 1 constant (0)
    );
    const premium = itemsTotal + PROCESSING_FEE;                    // 1 binding (premium), 1 invocation (+)
    return { premium };
  });
  return { results };
};
```

